#!/usr/bin/env node
/**
 * Generates src/generated/bootstrap-sql.ts from prisma/schema.prisma.
 *
 * The app uses this SQL to self-provision the database AT RUNTIME (first login
 * on a fresh deploy) when the tables don't exist yet — e.g. the user connected
 * a Postgres to Vercel after the build ran, so the build-time `db push` never
 * saw it. `prisma migrate diff` needs no live database: it diffs an empty
 * schema against schema.prisma and emits the full Postgres DDL.
 *
 * Runs automatically from `build` / `vercel-build`. The generated file is also
 * committed so `next dev` and tests work without a build step.
 */
import { execFileSync } from "node:child_process";
import { mkdirSync, writeFileSync } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const root = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");

const sql = execFileSync(
  "npx",
  [
    "prisma",
    "migrate",
    "diff",
    "--from-empty",
    "--to-schema-datamodel",
    "prisma/schema.prisma",
    "--script",
  ],
  { cwd: root, encoding: "utf8" }
);

const outDir = path.join(root, "src", "generated");
mkdirSync(outDir, { recursive: true });

const banner = `// AUTO-GENERATED by scripts/gen-bootstrap-sql.mjs — do not edit by hand.
// Full Postgres DDL for the Prisma schema, used by src/lib/bootstrap.ts to
// create missing tables at runtime (first request on a fresh database).
// Regenerated on every build; commit the result when the schema changes.

/* eslint-disable */
export const BOOTSTRAP_SQL = ${JSON.stringify(sql)};
`;

writeFileSync(path.join(outDir, "bootstrap-sql.ts"), banner);
console.log(
  `[gen-bootstrap-sql] Wrote src/generated/bootstrap-sql.ts (${sql.length} chars).`
);
